import { defineContract } from 'aether';

export default defineContract({
  name: 'tasks',
  description: 'Manages tasks, projects, and assignments within teams.',

  dependencies: {
    modules: ['auth'], // Depends on auth for user session and user context
  },

  exposes: {
    routes: [
      { method: 'GET', path: '/tasks', auth: true }, // List tasks for current user's team
    ],
    functions: [], // No functions exposed for other modules at this time
    types: ['Task'], // Expose the Task type for other modules to use
  },

  sideEffects: [
    'reads from: tasks table',
    'reads from: users table (indirectly via auth module for team context)',
  ],

  invariants: [
    'All tasks must belong to exactly one team.',
    'Users can only view tasks within their own team.',
    'Pagination parameters (limit, offset) must be non-negative.',
  ],
});
```
